// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before external posting API calls.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

// Deduplicate using n8n static data for persistence across executions on n8n Cloud
const staticData = $getWorkflowStaticData('global');

if (!staticData.posted_hashes) {
  staticData.posted_hashes = [];
}

const txHash = $input.first().json.tx_hash;

if (staticData.posted_hashes.includes(txHash)) {
  return [];
}

staticData.posted_hashes.push(txHash);

// Keep only last 500 hashes to stay within static data size limits (~256KB)
if (staticData.posted_hashes.length > 500) {
  staticData.posted_hashes = staticData.posted_hashes.slice(-500);
}

return $input.all();

// Rate limit check: max 6 posts/day per cadence.md
// NOTE: This node only CHECKS the count. The counter is incremented
// in the 'Increment Post Counter' node AFTER a successful post.
// This prevents invalid payloads and dry-run executions from
// consuming the daily limit.
const staticData = $getWorkflowStaticData('global');
const now = new Date();
const todayKey = now.toISOString().split('T')[0];

if (!staticData.daily_post_counts) {
  staticData.daily_post_counts = {};
}

// Clean up old date entries
for (const key of Object.keys(staticData.daily_post_counts)) {
  if (key !== todayKey) {
    delete staticData.daily_post_counts[key];
  }
}

const todayCount = staticData.daily_post_counts[todayKey] || 0;
const MAX_DAILY_POSTS = 6;

if (todayCount >= MAX_DAILY_POSTS) {
  // Rate limited: skip posting, return empty to halt pipeline
  return [{ json: { rate_limited: true, today_count: todayCount, max: MAX_DAILY_POSTS, tx_hash: $input.first().json.tx_hash } }];
}

// Pass through without incrementing. Counter incremented after successful post.
return [{ json: { ...($input.first().json), rate_limited: false, today_count: todayCount } }];

