const tx = $input.first().json;

// Chain name allowlist: reject unknown chains to prevent injection
// Case-insensitive comparison so 'ethereum', 'ETHEREUM', and 'Ethereum' all pass
const ALLOWED_CHAINS = ['bittensor', 'solana', 'ethereum', 'base', 'arbitrum', 'polygon', 'avalanche', 'bsc'];

const sourceChain = tx.source_chain;
const destChain = tx.dest_chain;

if (!ALLOWED_CHAINS.includes(String(sourceChain).toLowerCase()) || !ALLOWED_CHAINS.includes(String(destChain).toLowerCase())) {
  // Reject: unknown chain name, possible injection attempt
  return [{ json: { rejected: true, reason: 'Unknown chain name', source_chain: sourceChain, dest_chain: destChain } }];
}

// Explorer URL domain validation: only allow known block explorer domains
const ALLOWED_EXPLORER_DOMAINS = [
  'etherscan.io',
  'bscscan.com',
  'polygonscan.com',
  'arbiscan.io',
  'snowtrace.io',
  'basescan.org',
  'solscan.io',
  'solana.fm',
  'explorer.solana.com',
  'taostats.io',
  'ccip.chain.link'
];

let explorerUrl = '';
if (tx.explorer_url) {
  try {
    const parsed = new URL(tx.explorer_url);
    const domain = parsed.hostname.replace(/^www\./, '');
    if (ALLOWED_EXPLORER_DOMAINS.some(d => domain === d || domain.endsWith('.' + d))) {
      explorerUrl = tx.explorer_url;
    }
    // If domain not allowed, explorerUrl stays empty (URL is dropped)
  } catch (e) {
    // Invalid URL, drop it
  }
}

const amount = Number(tx.amount_tao).toLocaleString('en-US', {
  minimumFractionDigits: 0,
  maximumFractionDigits: 1
});

const tweet = `${amount} $TAO bridged from ${sourceChain} to ${destChain}.\n\nNon-custodial. Secured by @chainlink CCIP.\n\n#Bittensor #VoidAI #CrossChain`;

let tweetWithLink = tweet;
if (explorerUrl && (tweet.length + explorerUrl.length + 2) <= 280) {
  tweetWithLink = `${amount} $TAO bridged from ${sourceChain} to ${destChain}.\n\nNon-custodial. Secured by @chainlink CCIP.\n\n${explorerUrl}\n\n#Bittensor #VoidAI #CrossChain`;
}

const finalTweet = tweetWithLink.length <= 280 ? tweetWithLink : tweet;

return [{
  json: {
    rejected: false,
    tweet: finalTweet,
    tx_hash: tx.tx_hash,
    amount_tao: tx.amount_tao,
    source_chain: sourceChain,
    dest_chain: destChain,
    timestamp: tx.timestamp
  }
}];

