// Increment the daily post counter AFTER a successful post.
// This ensures invalid payloads, dry-run executions, and rejected
// chain names do not consume the daily rate limit.
const postResponse = $input.first().json;

// Only increment if the Post Tweet node returned a 2xx status
const statusCode = postResponse.statusCode || postResponse.status || 200;
if (statusCode < 200 || statusCode >= 300) {
  // Post failed, do not consume a rate limit slot
  return [{ json: { incremented: false, reason: 'Post returned non-2xx', statusCode } }];
}

const staticData = $getWorkflowStaticData('global');
const now = new Date();
const todayKey = now.toISOString().split('T')[0];

if (!staticData.daily_post_counts) {
  staticData.daily_post_counts = {};
}

const todayCount = staticData.daily_post_counts[todayKey] || 0;
staticData.daily_post_counts[todayKey] = todayCount + 1;

return [{ json: { ...postResponse, incremented: true, today_count: todayCount + 1 } }];
